// === Data Validation & Quality Flagging ===
// Runs ONCE for all incoming records so we can detect duplicate
// Company_UUIDs across the whole batch (not just per-row checks).

const items = $input.all();

// --- Pass 1: count UUID occurrences to detect batch-level duplicates ---
const uuidCounts = {};
for (const item of items) {
  const uuid = item.json.Company_UUID;
  if (uuid) uuidCounts[uuid] = (uuidCounts[uuid] || 0) + 1;
}

// --- Pass 2: validate each record and attach data_quality_flags ---
const results = [];
for (const item of items) {
  const r = { ...item.json };
  const flags = [];

  // Exports often deliver numbers as strings — normalise first.
  const amount = parseFloat(r.Amount_Due_USD);
  const dpd = parseFloat(r.DPD_days);
  const creditRaw = r.Credit_Line_USD;
  const creditLine =
    creditRaw === '' || creditRaw === undefined || creditRaw === null
      ? null
      : parseFloat(creditRaw);
  const status = (r.Record_status || '').toString().trim();

  // Field-level validations
  const amountValid = !isNaN(amount) && amount > 0;
  if (!amountValid) flags.push('Invalid amount');            // missing or <= 0

  const dpdValid = !isNaN(dpd) && dpd > 0;
  if (!dpdValid) flags.push('Invalid DPD');                  // missing or <= 0

  if (creditLine === null || isNaN(creditLine)) flags.push('Missing credit line');

  if (dpdValid && dpd > 365) flags.push('Aged 365+ days');

  if (status === 'Pending_review') flags.push('Pending review');

  // Batch-level validation
  if (r.Company_UUID && uuidCounts[r.Company_UUID] > 1) flags.push('Duplicate UUID');

  // Workable ONLY if amount + DPD are valid AND the account is Active.
  // (Pending_review is therefore never workable.)
  const workable = amountValid && dpdValid && status === 'Active';

  results.push({
    json: {
      ...r,
      // write back the cleaned/coerced values
      Amount_Due_USD: amountValid ? amount : r.Amount_Due_USD,
      DPD_days: dpdValid ? dpd : r.DPD_days,
      Credit_Line_USD: creditLine,
      data_quality_flags: flags,
      workable,
    },
  });
}

return results;

// === Deterministic Policy Engine ===
// Pure decision table. No randomness, no LLM, no external calls:
// the same input always yields the same recommended_policy.
// Only WORKABLE records get a policy; everything else passes through.

const items = $input.all();
const results = [];

for (const item of items) {
  const r = { ...item.json };

  if (!r.workable) {
    results.push({
      json: {
        ...r,
        recommended_policy: null,
        policy_rule_fired: null,
        upfront_required_usd: null,
      },
    });
    continue;
  }

  const amount = parseFloat(r.Amount_Due_USD);
  const dpd = parseFloat(r.DPD_days);

  let policy;
  let rule;
  let upfront = 0;

  if (dpd >= 1 && dpd <= 30) {
    if (amount < 10000) {
      policy = 'Full payment, no discount';
      rule = 'DPD_1_30__UNDER_10K';
    } else if (amount <= 50000) {
      policy = 'Full payment, no discount';
      rule = 'DPD_1_30__10K_TO_50K';
    } else {
      policy = '20% interest discount if 50% paid upfront';
      rule = 'DPD_1_30__OVER_50K';
      upfront = amount * 0.5;
    }
  } else if (dpd > 30) {
    policy = '40% interest discount if 50% paid upfront';
    rule = 'DPD_OVER_30';
    upfront = amount * 0.5;
  } else {
    // Safety net — a workable record should never have DPD <= 0.
    policy = 'Manual review';
    rule = 'UNCLASSIFIED';
  }

  results.push({
    json: {
      ...r,
      recommended_policy: policy,
      policy_rule_fired: rule,
      upfront_required_usd: Math.round(upfront * 100) / 100,
    },
  });
}

return results;

// === Assemble cleaned output + metadata summary, then serialise to JSON ===
// Runs once for all items. Consumes the FULL enriched batch (both
// workable and needs-review records) so the summary totals are complete.

const items = $input.all();
const accounts = items.map((i) => i.json);

const workable = accounts.filter((a) => a.workable);
const needsReview = accounts.filter((a) => !a.workable);

const duplicateUuidCount = accounts.filter((a) =>
  (a.data_quality_flags || []).includes('Duplicate UUID'),
).length;

// Total exposure = sum of every valid Amount_Due_USD in the batch.
const totalExposure = accounts.reduce((sum, a) => {
  const amt = parseFloat(a.Amount_Due_USD);
  return sum + (isNaN(amt) ? 0 : amt);
}, 0);

const output = {
  metadata: {
    generated_at: new Date().toISOString(),
    total_records: accounts.length,
    workable_count: workable.length,
    needs_review_count: needsReview.length,
    duplicate_uuid_count: duplicateUuidCount,
    total_exposure_usd: Math.round(totalExposure * 100) / 100,
  },
  accounts,
};

// Attach the JSON as binary data so the next node can write it to disk.
const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(JSON.stringify(output, null, 2)),
  'cleaned_accounts.json',
  'application/json',
);

return [{ json: output, binary: { data: binaryData } }];
